fun solve(landStartTime: Array<Long>, landDuration: Array<Long>, waterStartTime: Array<Long>, waterDuration: Array<Long>): Long {
    var minEndTime = Long.MAX_VALUE

    for (landI in landStartTime.indices) {
        for (waterJ in waterStartTime.indices) {
            // Calculate end time for land ride
            val landEndTime = max(landStartTime[landI], landStartTime[landI] + landDuration[landI])

            // Calculate end time for water ride
            val waterEndTime = max(waterStartTime[waterJ], waterStartTime[waterJ] + waterDuration[waterJ])

            // Calculate end time if land ride is done first
            val endLandFirst = max(landEndTime, waterStartTime[waterJ]) + waterDuration[waterJ]

            // Calculate end time if water ride is done first
            val endWaterFirst = max(waterEndTime, landStartTime[landI]) + landDuration[landI]

            // Update the minimum end time
            minEndTime = min(minEndTime, endLandFirst, endWaterFirst)
        }
    }

    return minEndTime
}
